SELECT FROM facility
active_yn = ANY(${activeYns}) AND main_open_yn = ANY(${mainOpenYns}) AND kind::text = ANY(${kinds}) AND name ILIKE '%' || #{q} || '%'
ORDER BY sort_order ASC, created_at DESC ${limitOffset}

SELECT 
FROM facility
WHERE id = ${id}
AND active_yn = #{activeYn}
LIMIT 1
